compliant:
#include <stdexcept>
#include <system_error>

// Compliant: Catching specific exception
void processOperation() {
    try {
        performSystemCall();
    } catch (const std::system_error& ex) {  // Specific exception
        handleSystemError(ex);
    }
}

// Another compliant example with multiple specific catches
void fileOperation() {
    try {
        readFile();
        writeFile();
    } catch (const std::ios_base::failure& ex) {
        handleFileError(ex);
    } catch (const std::bad_alloc& ex) {
        handleMemoryError(ex);
    }
}

// Compliant: Catching specific logic error types
void validateInput() {
    try {
        checkInputRange();
    } catch (const std::invalid_argument& ex) {
        handleInvalidArgument(ex);
    } catch (const std::out_of_range& ex) {
        handleRangeError(ex);
    }
}

// Compliant: Using specific custom exceptions
class FileNotFoundException : public std::runtime_error {
public:
    FileNotFoundException(const std::string& filename) 
        : std::runtime_error("File not found: " + filename) {}
};

void loadConfiguration() {
    try {
        openConfigFile();
    } catch (const FileNotFoundException& ex) {
        useDefaultConfiguration();
    }
}
